export function IcoRouteBar() {
  const { palette } = useIlloStyle();
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {/* Route bar background */}
      <rect x="20" y="52" width="160" height="16" rx="8" fill={palette.mid} opacity="0.30" />
      {/* Progress fill */}
      <rect x="20" y="52" width="95" height="16" rx="8" fill={palette.accent} opacity="0.75" />
      {/* Vehicle icon (small triangle) at progress point */}
      <polygon points="115,44 108,52 122,52" fill={palette.accent} />
      {/* Destination pin at right end */}
      <circle cx="180" cy="52" r="10" fill={palette.accent} />
      <circle cx="180" cy="52" r="4.5" fill={palette.dark} />
      <polygon points="180,62 174,52 186,52" fill={palette.accent} />
    </svg>
  );
}
